import type { CheckboxProps } from ':components/Checkbox/Checkbox.types';
import type { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import { HTMLAttributes } from 'react';
import { TestComponentProps } from 'src/types/test-component';
import type { ToolbarItemProps } from './ToolbarItem';
/**
 * Пропсы компонента Toolbar — контейнер команд/действий.
 */
export interface ToolbarProps extends TestComponentProps, HTMLAttributes<HTMLDivElement> {
    /** Дополнительный CSS-класс корня. */
    className?: string;
    /**
     * Размер тулбара:
     * - `large` — высота ~56 px (списки/таблицы, дефолт для десктопа);
     * - `medium` — высота ~48 px (плотные интерфейсы).
     * @default 'medium'
     */
    size?: 'large' | 'medium';
    /**
     * Пропсы чекбокса массового выбора (встроенный Label не используется).
     * Если не задан — чекбокс не показывается.
     */
    checkbox?: Omit<CheckboxProps, 'label'>;
    /**
     * Правая иконка тулбара (например, настройки).
     */
    rightIcon?: {
        /** Имя иконки из дизайн-токенов. */
        iconName: Icons;
        /** Колбэк по клику по правой иконке. */
        onClick?: () => void;
    };
    /**
     * Счётчик выбранных элементов.
     */
    counter?: {
        /** Текст счётчика (например, "Выбрано: 3"). */
        label: string;
        /** Неактивный стиль счётчика (для пустого выбора). */
        disabled?: boolean;
    };
    /**
     * Дочерние элементы — `ToolbarItem` и/или `Divider`.
     * Альтернатива `values`.
     */
    children?: React.ReactNode;
    /**
     * Включить механизм «Ещё»: переполняющие элементы
     * скрываются в выпадающее меню.
     * @default false
     */
    enableShowMore?: boolean;
    /**
     * Описание элементов через объектную схему.
     * Массив групп, каждая группа отделяется `Divider`.
     * Взаимоисключимо с `children`.
     */
    values?: ToolbarItemProps[][];
}
